// 游戏的全局变量
ArrayList<Trash> trashItems; // 储存垃圾的列表
Hook claw; // 钩爪对象
boolean isHoldingTrash = false;

// 游戏中的常量
final int SKY_HEIGHT = 150;

// 设置游戏的初始状态
void setup() {
  size(800, 600);
  noCursor(); // 隐藏光标
  trashItems = new ArrayList<Trash>();

  // 添加一些垃圾物体
  trashItems.add(new Trash(100, 400, 20, color(150, 0, 0))); // 参数分别是x, y, radius和颜色
  trashItems.add(new Trash(300, 500, 20, color(0, 0, 150)));

  // 钩爪的初始化
  claw = new Hook(width/2, SKY_HEIGHT);
}

// 游戏画面的更新
void draw() {
  background(255);
  drawEnvironment();

  for (Trash trash : trashItems) {
    trash.update();
    trash.display();
  }

  // 更新并显示钩爪
  claw.update();
  claw.display();

  checkCollisions();
}

void drawEnvironment() {
  // 画上半边天空
  fill(135, 206, 235); // 浅蓝色
  noStroke();
  rect(0, 0, width, SKY_HEIGHT);
  // 画下半边大海
  fill(0, 105, 148); // 海洋蓝
  rect(0, SKY_HEIGHT, width, height - SKY_HEIGHT);
}

// 鼠标点击事件处理
void mousePressed() {
  claw.swing();
}

// 垃圾类
class Trash {
  float x, y;
  float radius; // 垃圾半径
  color col; // 垃圾颜色
  boolean isHooked = false; // 是否被钩住

  Trash(float x_, float y_, float r_, color c_) {
    x = x_;
    y = y_;
    radius = r_; // 初始化半径
    col = c_; // 初始化颜色
  }

  void update() {
    // 在这里可以添加垃圾的移动和碰撞逻辑（如果需要的话）
  }

  void display() {
    fill(col);
    noStroke();
    ellipse(x, y, radius * 2, radius * 2); 
  }
}

// 钩爪类
class Hook {
  float x, y; // 钩爪的位置
  float length = 0; // 钩爪绳子的长度
  float swingDirection = 1; // 钩爪摇摆方向
  boolean isDropping = false; // 钩爪是否正在下降
  float dropSpeed = 5; // 钩爪的下降速度
  Trash hookedTrash = null; // 钩住的垃圾

  Hook(float x_, float y_) {
    x = x_;
    y = y_;
  }

  void update() {
    // 控制钩爪左右摇摆
    if (!isDropping && length == 0) {
      x += swingDirection;
      if (x < 0 || x > width) swingDirection *= -1;
    } 
    // 控制钩爪下降
    else if (isDropping) {
      if (y + length < height) {
        length += dropSpeed;
        // 当钩爪进入水中时开始减缓速度
        if (y + length > SKY_HEIGHT) {
          dropSpeed *= 0.99; // 减速程度较小
        }
      } else {
        // 钩爪触碰到屏幕底部，开始上升
        isDropping = false; 
      }
    }
    // 控制钩爪上升
    else {
      length -= dropSpeed; // 使用与下降相同的速度上升
      dropSpeed /= 0.99; // 上升过程中速度逐步恢复

      // 如果钩爪有抓到垃圾，把垃圾拉上来
      if (hookedTrash != null) {
        hookedTrash.y = y + length;
      }

      // 当钩爪回到起始位置时，将物体移出游戏
      if (length <= 0) {
        length = 0;
        dropSpeed = 5; // 重置速度
        isDropping = false; // 停止上升
        if (hookedTrash != null) {
          trashItems.remove(hookedTrash);
          hookedTrash = null;
        }
      }
    }
  }




  void display() {
    stroke(0); line(x, y, x, y + length); // 钩爪线
    fill(160); ellipse(x, y + length, 15, 15); // 钩爪
  }

  void swing() {
    if (!isDropping) {
      isDropping = true;
      swingDirection = 0; // 停止摇摆
    }
  }
}

// 检查钩爪和垃圾的碰撞
void checkCollisions() {
  for (Trash trash : trashItems) {
    float d = dist(claw.x, claw.y + claw.length, trash.x, trash.y);
    if (d < trash.radius && !isHoldingTrash) {
      isHoldingTrash = true;
      trash.isHooked = true;
      claw.hookedTrash = trash;
    }
  }
