          trashItems.remove(hookedTrash);
          hookedTrash = null;
        }
        // 钩爪到顶点后恢复摇摆
        swingDirection = (swingDirection == 0) ? 1 : swingDirection;
        // 钩爪到顶点后释放垃圾
        isHoldingTrash = false;
      }
    }
  }

  void display() {
    stroke(0); 
    line(x, y, x, y + length); // 钩爪线
    fill(160); 
    ellipse(x, y + length, 15, 15); // 钩爪
  }

  // 开始下降或者摇摆
  void swing() {
    if (!isDropping) {
      isDropping = true;
      swingDirection = 0; // 停止摇摆
    }
  }
}

// 检查钩爪和垃圾的碰撞
