```java
class Trash {
  float x, y;
  float radius;
  color col;
  boolean isHooked = false;
  float vx = 0; // X轴速度
  float vy = 0; // Y轴速度

  Trash(float x_, float y_, float r_, color c_) {
    x = x_;
    y = y_;
    radius = r_;
    col = c_;
  }

  void update() {
    x += vx;
    y += vy;

    // 让速度慢慢衰减
    vx *= 0.99;
    vy *= 0.99;
  }

  void display() {
    fill(col);
    noStroke();
    ellipse(x, y, radius*2, radius*2);
  }

  // 与另一个垃圾物体碰撞的响应
  void collide(Trash other) {
    // 计算碰撞法线
    float nx = other.x - this.x;
    float ny = other.y - this.y;
    float dist = sqrt(nx*nx + ny*ny);

    // 正常化法线
    nx /= dist;
    ny /= dist;

    // 计算相对速度的法线分量
